import React, { useState, useEffect } from 'react';

function Dashboard() {
  const [trashData, setTrashData] = useState([]);
  const [adminData, setAdminData] = useState([]);
  const [activeAdmin, setActiveAdmin] = useState('');
  // State untuk kontrol menu yang aktif (Dashboard atau Admin)
  const [activeMenu, setActiveMenu] = useState('dashboard');

  // Fungsi untuk mengambil semua data dari Flask Backend
  const fetchData = async () => {
    try {
      // Ambil data monitoring sampah
      const resTrash = await fetch('http://127.0.0.1:5000/api/trash');
      const resultTrash = await resTrash.json();
      setTrashData(resultTrash);

      // Ambil data daftar admin
      const resAdmins = await fetch('http://127.0.0.1:5000/api/admins');
      const resultAdmins = await resAdmins.json();
      setAdminData(resultAdmins);
    } catch (error) {
      console.error("Gagal mengambil data dari server:", error);
    }
  };

  useEffect(() => {
    // Ambil identitas admin yang sedang login
    const name = localStorage.getItem("nama_aktif");
    setActiveAdmin(name || "Admin");

    fetchData();
    // Auto-refresh data setiap 5 detik agar real-time
    const interval = setInterval(fetchData, 5000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={styles.appContainer}>
      {/* Import Font Poppins agar desain terlihat modern & kekinian */}
      <style>
        @import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;600;700&display=swap');
      </style>

      {/* --- SIDEBAR KIRI (TEMA HIJAU) --- */}
      <aside style={styles.sidebar}>
        <div style={styles.logoArea}>
          <div style={styles.logoIcon}>S</div>
          <span style={styles.logoText}>SMART BIN</span>
        </div>

        <nav style={styles.navMenu}>
          <div 
            style={activeMenu === 'dashboard' ? styles.navItemActive : styles.navItem} 
            onClick={() => setActiveMenu('dashboard')}
          >
            <span style={styles.navIcon}>📊</span> Dashboard
          </div>

          <div 
            style={activeMenu === 'admin' ? styles.navItemActive : styles.navItem} 
            onClick={() => setActiveMenu('admin')}
          >
            <span style={styles.navIcon}>👥</span> User Admin
          </div>

          <div style={styles.navItem} onClick={() => { localStorage.clear(); window.location.href = "/"; }}>
            <span style={styles.navIcon}>🚪</span> Keluar Sistem
          </div>
        </nav>
      </aside>

      {/* --- KONTEN UTAMA (KANAN) --- */}
      <main style={styles.mainContent}>
        <header style={styles.topHeader}>
          <div style={styles.breadcrumb}>
            Dashboard {activeMenu === 'dashboard' ? '> Monitoring' : '> Manajemen Admin'}
          </div>
          <div style={styles.userProfile}>
            <span style={styles.userName}>{activeAdmin}</span>
            <div style={styles.avatar}>👤</div>
          </div>
        </header>

        <div style={styles.contentWrapper}>
          <h2 style={styles.welcomeText}>
            {activeMenu === 'dashboard' ? 'Monitoring Real-time' : 'Daftar Pengelola Admin'}
          </h2>

          {activeMenu === 'dashboard' ? (
            <>
              {/* KARTU STATISTIK (Sudah diperbaiki agar tidak ada warning duplicate props) */}
              <div style={styles.statsGrid}>
                <div style={styles.statCard}>
                  <div style={{...styles.statIconBox, color: '#008f68'}}>🗑️</div>
                  <div>
                    <div style={styles.statValue}>{trashData.length}</div>
                    <div style={styles.statLabel}>Total Data Log</div>
                  </div>
                </div>
                <div style={styles.statCard}>
                  <div style={{...styles.statIconBox, color:'#f39c12'}}>👤</div>
                  <div>
                    <div style={styles.statValue}>{adminData.length}</div>
                    <div style={styles.statLabel}>Admin Terdaftar</div>
                  </div>
                </div>
                <div style={styles.statCard}>
                  <div style={{...styles.statIconBox, color:'#2ecc71'}}>📶</div>
                  <div>
                    <div style={styles.statValue}>Online</div>
                    <div style={styles.statLabel}>Status Sistem</div>
                  </div>
                </div>
              </div>

              {/* TABEL DATA MONITORING SAMPAH */}
              <div style={styles.tableSection}>
                <h3 style={styles.tableTitle}>📊 Tabel Kapasitas Sampah</h3>
                <div style={styles.tableCard}>
                  <table style={styles.table}>
                    <thead>
                      <tr>
                        <th style={styles.th}>ID BIN</th>
                        <th style={styles.th}>TIPE</th>
                        <th style={styles.th}>KAPASITAS</th>
                        <th style={styles.th}>STATUS</th>
                        <th style={styles.th}>WAKTU UPDATE</th>
                      </tr>
                    </thead>
                    <tbody>
                      {trashData.map((item, index) => (
                        <tr key={index} style={styles.tr}>
                          <td style={styles.td}><strong>{item.bin_id}</strong></td>
                          <td style={styles.td}>{item.type}</td>
                          <td style={styles.td}>
                            <div style={styles.progressBar}>
                              <div style={{
                                ...styles.progressFill, 
                                width: `${item.percentage}%`, 
                                backgroundColor: item.percentage > 85 ? '#e74c3c' : '#00a37c'
                              }}></div>
                            </div>
                            <span style={{fontSize:'12px', fontWeight:'600'}}>{Math.round(item.percentage)}%</span>
                          </td>
                          <td style={styles.td}>
                            <span style={item.status === 'penuh' ? styles.badgeRed : styles.badgeGreen}>
                              {item.status}
                            </span>
                          </td>
                          <td style={styles.td}>{new Date(item.created_at).toLocaleTimeString('id-ID')}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </>
          ) : (
            /* TABEL ADMIN (Hanya muncul jika menu User Admin diklik) */
            <div style={styles.tableSection}>
              <h3 style={styles.tableTitle}>👥 Database Admin Sistem</h3>
              <div style={styles.tableCard}>
                <table style={styles.table}>
                  <thead>
                    <tr>
                      <th style={styles.th}>NAMA LENGKAP</th>
                      <th style={styles.th}>ALAMAT EMAIL</th>
                      <th style={styles.th}>ROLE</th>
                      <th style={styles.th}>AKSES</th>
                    </tr>
                  </thead>
                  <tbody>
                    {adminData.map((admin, index) => (
                      <tr key={index} style={styles.tr}>
                        <td style={styles.td}><strong>{admin.name}</strong></td>
                        <td style={styles.td}>{admin.email}</td>
                        <td style={styles.td}>Administrator</td>
                        <td style={styles.td}><span style={styles.badgeGreen}>Granted</span></td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

// 🎨 KONFIGURASI STYLE (TEMA HIJAU MODERN)
const styles = {
  appContainer: { display: 'flex', minHeight: '100vh', backgroundColor: '#008f68', fontFamily: "'Poppins', sans-serif" },

  // SIDEBAR
  sidebar: { width: '260px', backgroundColor: '#008f68', color: '#fff', padding: '30px 0', boxShadow: '5px 0 15px rgba(0,0,0,0.05)' },
  logoArea: { display: 'flex', alignItems: 'center', padding: '0 30px', marginBottom: '50px' },
  logoIcon: { backgroundColor: '#fff', color: '#008f68', width: '38px', height: '38px', borderRadius: '10px', display: 'flex', justifyContent: 'center', alignItems: 'center', fontWeight: 'bold', marginRight: '12px', fontSize: '20px' },
  logoText: { fontSize: '22px', fontWeight: '700', letterSpacing: '1px' },
  navMenu: { display: 'flex', flexDirection: 'column' },
  navItem: { padding: '16px 30px', cursor: 'pointer', color: '#c1e1d8', transition: '0.3s', display: 'flex', alignItems: 'center', fontSize: '14px' },
  navItemActive: { padding: '16px 30px', cursor: 'pointer', backgroundColor: 'rgba(255,255,255,0.15)', borderLeft: '5px solid #fff', color: '#fff', display: 'flex', alignItems: 'center', fontSize: '14px', fontWeight: '600' },
  navIcon: { marginRight: '15px', fontSize: '18px' },

  // MAIN CONTENT
  mainContent: { flex: 1, backgroundColor: '#f5fcf9', borderTopLeftRadius: '45px', padding: '40px', overflowY: 'auto' },
  topHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' },
  breadcrumb: { color: '#999', fontSize: '13px', fontWeight: '500' },
  userProfile: { display: 'flex', alignItems: 'center', backgroundColor: '#fff', padding: '10px 18px', borderRadius: '35px', boxShadow: '0 4px 12px rgba(0,0,0,0.03)' },
  userName: { marginRight: '12px', fontWeight: '600', color: '#333', fontSize: '14px' },
  avatar: { width: '32px', height: '32px', borderRadius: '50%', backgroundColor: '#f0f0f0', display:'flex', justifyContent:'center', alignItems:'center', fontSize:'14px' },

  contentWrapper: { padding: '0 5px' },
  welcomeText: { fontSize: '26px', fontWeight: '700', marginBottom: '35px', color: '#2c3e50' },

  // STATS
  statsGrid: { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '28px', marginBottom: '45px' },
  statCard: { backgroundColor: '#fff', padding: '28px', borderRadius: '22px', display: 'flex', alignItems: 'center', boxShadow: '0 8px 24px rgba(0,143,104,0.06)' },
  statIconBox: { fontSize: '30px', marginRight: '22px', width: '60px', height: '60px', backgroundColor: '#f0fbf7', borderRadius: '18px', display: 'flex', justifyContent: 'center', alignItems: 'center' },
  statValue: { fontSize: '24px', fontWeight: '700', color: '#008f68' },
  statLabel: { fontSize: '14px', color: '#999', fontWeight: '500' },

  // TABLES
  tableSection: { marginTop: '20px' },
  tableTitle: { fontSize: '18px', fontWeight: '700', marginBottom: '22px', color: '#2c3e50' },
  tableCard: { backgroundColor: '#fff', borderRadius: '25px', padding: '28px', boxShadow: '0 10px 30px rgba(0,0,0,0.02)' },
  table: { width: '100%', borderCollapse: 'collapse' },
  th: { textAlign: 'left', padding: '16px', color: '#bbb', fontSize: '12px', borderBottom: '1px solid #f8f9fa', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.5px' },
  td: { padding: '20px 16px', color: '#444', fontSize: '14px', borderBottom: '1px solid #fcfcfc' },
  tr: { transition: '0.2s' },

  // PROGRESS & BADGES
  progressBar: { width: '130px', height: '9px', backgroundColor: '#f1f1f1', borderRadius: '12px', marginBottom: '6px' },
  progressFill: { height: '100%', borderRadius: '12px', transition: 'width 0.8s cubic-bezier(0.4, 0, 0.2, 1)' },
  badgeGreen: { backgroundColor: '#d1e7dd', color: '#0f5132', padding: '7px 16px', borderRadius: '35px', fontSize: '11px', fontWeight: '700' },
  badgeRed: { backgroundColor: '#f8d7da', color: '#842029', padding: '7px 16px', borderRadius: '35px', fontSize: '11px', fontWeight: '700' },
};

export default Dashboard;
